use actix_web::{web, App, HttpRequest, HttpResponse, Responder};
use reqwest;
use serde_json::Value;

async fn handle_proxy(req: HttpRequest) -> Result<HttpResponse, Box<dyn std::error::Error>> {
    let url = match req.match_info().query("url") {
        None => return Err("No URL provided".into()),
        Some(s) => s.parse().unwrap(), // in a production service you'd want to handle this better than just panic
    };
    
    let client = reqwest::Client::new();
    match client.get(&url).send().await {
        Ok(response) => match response.text().await {
            Ok(body) => {
                return Ok(HttpResponse::Ok()
                    .content_type("application/json")
                    .body(body));
            }
            Err(e) => println!("Failed to get body: {}", e),
        },
        Err(e) => println!("Failed to send request: {}", e),
    };
    
    Ok(HttpResponse::NotFound().body("Not found")) // Return 404 if the URL does not return a valid response
}

